function separate_paren_groups(paren_string) {
    const result = [];
    let currentGroup = "";
    let balance = 0;

    // Remove all spaces from the input string
    const cleanString = paren_string.replace(/\s/g, '');

    for (let i = 0; i < cleanString.length; i++) {
        const char = cleanString[i];
        currentGroup += char;

        if (char === '(') {
            balance++;
        } else if (char === ')') {
            balance--;
        }

        // When we've closed a complete group
        if (balance === 0) {
            result.push(currentGroup);
            currentGroup = "";
        }
    }

    return result;
}
