function mean_absolute_deviation(numbers) {
    if (numbers.length === 0) return 0;

    // Calculate the mean
    const mean = numbers.reduce((sum, num) => sum + num, 0) / numbers.length;

    // Calculate the sum of absolute differences from the mean
    const sumOfAbsoluteDifferences = numbers.reduce((sum, num) => {
        return sum + Math.abs(num - mean);
    }, 0);

    // Return the average of absolute differences
    return sumOfAbsoluteDifferences / numbers.length;
}
