function parse_nested_parens(paren_string) {
    const groups = paren_string.split(' ');
    const result = [];

    for (const group of groups) {
        let maxDepth = 0;
        let currentDepth = 0;

        for (let i = 0; i < group.length; i++) {
            const char = group[i];
            if (char === '(') {
                currentDepth++;
                maxDepth = Math.max(maxDepth, currentDepth);
            } else if (char === ')') {
                currentDepth--;
            }
        }

        result.push(maxDepth);
    }

    return result;
}
