function make_palindrome(string) {
    if (string === "") return "";

    // Find the longest palindromic postfix
    for (let i = 0; i < string.length; i++) {
        const suffix = string.substring(i);
        if (isPalindrome(suffix)) {
            // Append the reverse of the prefix to make palindrome
            const prefix = string.substring(0, i);
            return string + prefix.split('').reverse().join('');
        }
    }

    // If no palindromic postfix found (shouldn't happen), append reverse of entire string except last char
    return string + string.substring(0, string.length - 1).split('').reverse().join('');
}

