    const digits = x.toString();
    const numDigits = digits.length;

    if (shift > numDigits) {
        return digits.split('').reverse().join('');
    }

    shift = shift % numDigits;

    if (shift === 0) {
        return digits;
    }

    const shifted = digits.slice(-shift) + digits.slice(0, -shift);
