```javascript
function starts_one_ends(n) {
    if (n === 1) {
        return 1;
    }

    // Numbers that start with 1: 10^(n-1) possibilities
    // Numbers that end with 1: 9 * 10^(n-2) possibilities
    // Numbers that both start and end with 1: 10^(n-2) possibilities

    const startWithOne = Math.pow(10, n - 1);
    const endWithOne = 9 * Math.pow(10, n - 2);
    const bothStartAndEndWithOne = Math.pow(10, n - 2);

    return startWithOne + endWithOne - bothStartAndEndWithOne;
}
