    // Calculate the sum of digits in N
    let sum = 0;
    let temp = N;

    if (temp === 0) {
        sum = 0;
    } else {
        while (temp > 0) {
            sum += temp % 10;
            temp = Math.floor(temp / 10);
        }
    }

    // Convert the sum to binary and return as string
    return sum.toString(2);
}
