function get_row(lst, x) {
    const result = [];

    for (let row = 0; row < lst.length; row++) {
        for (let col = 0; col < lst[row].length; col++) {
            if (lst[row][col] === x) {
                result.push([row, col]);
            }
        }
    }

    // Sort by row ascending, then by column descending within each row
    result.sort((a, b) => {
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Sort by row ascending
        }
        return b[1] - a[1]; // Sort by column descending
