            result += String.fromCharCode(shifted);
        } else if (char >= 'A' && char <= 'Z') {
            let code = char.charCodeAt(0);
            let shifted = ((code - 65 + 4) % 26) + 65;
            result += String.fromCharCode(shifted);
        } else {
            result += char;
        }
    }
