function check_dict_case(dict) {
    const keys = Object.keys(dict);

    // Return false if object is empty
    if (keys.length === 0) {
        return false;
    }

    // Check if all keys are strings
    for (let key of keys) {
        if (typeof key !== 'string') {
            return false;
        }
    }

    // Check if all keys are lowercase or all keys are uppercase
    const allLower = keys.every(key => key === key.toLowerCase());
    const allUpper = keys.every(key => key === key.toUpperCase());

    return allLower || allUpper;
}
