function rounded_avg(n, m) {
    if (n > m) {
        return -1;
    }

    // Calculate sum of integers from n to m
    const count = m - n + 1;
    const sum = (count * (n + m)) / 2;

    // Calculate average and round to nearest integer
    const average = Math.round(sum / count);

    // Convert to binary string with "0b" prefix
    return "0b" + average.toString(2);
}
