    function sumOfDigits(num) {
        if (num === 0) return 0;

        let sum = 0;
        let isNegative = num < 0;
        let absNum = Math.abs(num);

        // Handle the first digit specially for negative numbers
        let digits = absNum.toString().split('').map(Number);

        if (isNegative) {
            sum += -digits[0];
            for (let i = 1; i < digits.length; i++) {
                sum += digits[i];
            }
        } else {
            for (let digit of digits) {
                sum += digit;
            }
        }

        return sum;
    }

    let count = 0;
    for (let num of arr) {
        if (sumOfDigits(num) > 0) {
            count++;
        }
    }

    return count;
}
