function move_one_ball(arr) {
    if (arr.length === 0) {
        return true;
    }

    // Create a sorted version of the array
    const sorted = [...arr].sort((a, b) => a - b);

    // Try all possible right shifts
    for (let shifts = 0; shifts < arr.length; shifts++) {
        let isMatch = true;

        // Check if current shift produces sorted array
        for (let i = 0; i < arr.length; i++) {
            const shiftedIndex = (i + shifts) % arr.length;
            if (arr[shiftedIndex] !== sorted[i]) {
                isMatch = false;
                break;
            }
        }

        if (isMatch) {
            return true;
        }
    }

    return false;
}
