```javascript
function histogram(test) {
    if (test === "") {
        return {};
    }

    const letters = test.split(" ");
    const countMap = {};

    // Count occurrences of each letter
    for (const letter of letters) {
        countMap[letter] = (countMap[letter] || 0) + 1;
    }

    // Find the maximum count
    const maxCount = Math.max(...Object.values(countMap));

    // Filter letters that have the maximum count
    const result = {};
    for (const [letter, count] of Object.entries(countMap)) {
        if (count === maxCount) {
            result[letter] = count;
        }
    }

    return result;
}
```

