function reverse_delete(s, c) {
    // Create a set of characters to delete for faster lookup
    const deleteChars = new Set(c);

    // Filter out characters that are in the delete set
    const filtered = s.split('').filter(char => !deleteChars.has(char)).join('');

    // Check if the filtered string is palindrome
    const reversed = filtered.split('').reverse().join('');
    const isPalindrome = filtered === reversed;

    return [filtered, isPalindrome];
