function get_closest_vowel(word) {
    if (word.length < 3) return "";

    const vowels = new Set(['a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U']);

    // Start from the right side, excluding the last character
    for (let i = word.length - 2; i >= 1; i--) {
        const char = word[i];
        const prevChar = word[i - 1];
        const nextChar = word[i + 1];

        // Check if current character is a vowel
        if (vowels.has(char)) {
            // Check if both adjacent characters are consonants
            if (!vowels.has(prevChar) && !vowels.has(nextChar)) {
                return char;
            }
        }
    }

    return "";
}
