function match_parens(lst) {
    function getBalance(s) {
        let balance = 0;
        let maxBalance = 0;
        for (let char of s) {
            if (char === '(') {
                balance++;
            } else {
                balance--;
            }
            maxBalance = Math.max(maxBalance, balance);
        }
        return { balance, maxBalance };
    }

    const [s1, s2] = lst;
    const b1 = getBalance(s1);
    const b2 = getBalance(s2);

    // Try order 1: s1 + s2
    if (b1.balance >= 0 && b2.balance >= 0 && b1.maxBalance >= -b2.balance) {
        return "Yes";
    }

    // Try order 2: s2 + s1
