function valid_date(date) {
    // Check if date string is not empty
    if (!date || date.length === 0) {
        return false;
    }

    // Check if format is mm-dd-yyyy (using regex)
    const format = /^(\d{2})-(\d{2})-(\d{4})$/;
    const match = date.match(format);

    if (!match) {
        return false;
    }

    const month = parseInt(match[1]);
    const day = parseInt(match[2]);
    const year = parseInt(match[3]);

    // Check if month is valid (1-12)
    if (month < 1 || month > 12) {
        return false;
    }

    // Check if day is valid based on month
    const daysInMonth = [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

    // For February (month 2), we allow up to 29 days (leap year consideration)
    if (day < 1 || day > daysInMonth[month - 1]) {
        return false;
    }

    return true;
}
