function prod_signs(arr) {
    if (arr.length === 0) {
        return undefined;
    }

    let sum = 0;
    let product = 1;

    for (let num of arr) {
        sum += Math.abs(num);
        if (num > 0) {
            product *= 1;
        } else if (num < 0) {
            product *= -1;
        } else {
            product *= 0;
        }
    }

    return sum * product;
}
