function minPath(grid, k) {
    const n = grid.length;
    const directions = [[0, 1], [1, 0], [0, -1], [-1, 0]];

    // Helper function to check if coordinates are valid
    const isValid = (row, col) => row >= 0 && row < n && col >= 0 && col < n;

    // Generate all possible paths of length k starting from each cell
    let minPathArray = null;

    // DFS function to explore paths
    function dfs(row, col, path, remainingSteps) {
        if (remainingSteps === 0) {
            if (minPathArray === null || path < minPathArray) {
                minPathArray = [...path];
            }
            return;
        }

        // Early termination: if current path is already lexicographically greater
        if (minPathArray !== null) {
            let isGreater = false;
            for (let i = 0; i < path.length; i++) {
                if (path[i] > minPathArray[i]) {
                    isGreater = true;
                    break;
                } else if (path[i] < minPathArray[i]) {
                    break;
                }
            }
            if (isGreater) return;
        }

        // Explore neighbors
        for (const [dr, dc] of directions) {
            const newRow = row + dr;
            const newCol = col + dc;

            if (isValid(newRow, newCol)) {
                path.push(grid[newRow][newCol]);
                dfs(newRow, newCol, path, remainingSteps - 1);
                path.pop();
            }
        }
    }

    // Start DFS from each cell
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            dfs(i, j, [grid[i][j]], k - 1);
        }
    }

    return minPathArray;
}
