function digits(n) {
    let product = 1;
    let hasOddDigit = false;

    while (n > 0) {
        let digit = n % 10;
        if (digit % 2 === 1) {
            product *= digit;
            hasOddDigit = true;
        }
        n = Math.floor(n / 10);
    }

    return hasOddDigit ? product : 0;
}

