function is_nested(string) {
    let maxDepth = 0;
    let currentDepth = 0;

    for (let i = 0; i < string.length; i++) {
        if (string[i] === '[') {
            currentDepth++;
            maxDepth = Math.max(maxDepth, currentDepth);
        } else if (string[i] === ']') {
            currentDepth--;
        }
    }

    // If max depth is greater than 1, there's nesting
    return maxDepth > 1;
}
