function is_equal_to_sum_even(n) {
    // The smallest sum of 4 positive even numbers is 2+2+2+2 = 8
    // Any number less than 8 cannot be expressed as sum of 4 positive even numbers
    if (n < 8) {
        return false;
    }

    // The sum of 4 even numbers is always even
    // So n must be even to be expressible as sum of 4 even numbers
    if (n % 2 !== 0) {
        return false;
    }

    // If n is even and >= 8, it can always be expressed as sum of 4 positive even numbers
    // For example: n = 8 -> 2+2+2+2
    //              n = 10 -> 2+2+2+4
    //              n = 12 -> 2+2+4+4
    //              etc.
    return true;
}
