function file_name_check(file_name) {
    // Check if there's exactly one dot
    const dotCount = (file_name.match(/\./g) || []).length;
    if (dotCount !== 1) {
        return 'No';
    }

    // Split the filename into name and extension
    const parts = file_name.split('.');
    const name = parts[0];
    const extension = parts[1];

    // Check if the name part is not empty
    if (name.length === 0) {
        return 'No';
    }

    // Check if the name starts with a letter
    if (!/^[a-zA-Z]/.test(name)) {
        return 'No';
    }

    // Check if the extension is valid
    const validExtensions = ['txt', 'exe', 'dll'];
    if (!validExtensions.includes(extension)) {
        return 'No';
    }

    // Count digits in the entire filename
    const digitCount = (file_name.match(/\d/g) || []).length;
    if (digitCount > 3) {
        return 'No';
    }

    return 'Yes';
}
