function simplify(x, n) {
    // Parse the fractions
    const [num1, den1] = x.split('/').map(Number);
    const [num2, den2] = n.split('/').map(Number);

    // Multiply the fractions: (num1/den1) * (num2/den2) = (num1*num2)/(den1*den2)
    const resultNum = num1 * num2;
    const resultDen = den1 * den2;

    // Check if the result is a whole number (denominator divides numerator evenly)
    return resultNum % resultDen === 0;
}
