function Strongest_Extension(class_name, extensions) {
    let strongestExt = extensions[0];
    let maxStrength = calculateStrength(extensions[0]);

    for (let i = 1; i < extensions.length; i++) {
        let strength = calculateStrength(extensions[i]);
        if (strength > maxStrength) {
