function calculateStrength(extension) {
    let capCount = 0;
    let smCount = 0;

    for (let char of extension) {
        if (char >= 'A' && char <= 'Z') {
            capCount++;
        } else if (char >= 'a' && char <= 'z') {
            smCount++;
        }
    }

    return capCount - smCount;
}
