function right_angle_triangle(a, b, c) {
    // Sort the sides to identify the largest side (potential hypotenuse)
    const sides = [a, b, c].sort((x, y) => x - y);

    // Check if it's a valid triangle first
    if (sides[0] <= 0 || sides[1] <= 0 || sides[2] <= 0) {
        return false;
    }

    // Apply Pythagorean theorem: a² + b² = c²
    // Using the sorted array where sides[2] is the largest
    return Math.abs(sides[0] * sides[0] + sides[1] * sides[1] - sides[2] * sides[2]) < 1e-10;
}
