```javascript
function do_algebra(operator, operand) {
    let result = operand[0];

    for (let i = 0; i < operator.length; i++) {
        const op = operator[i];
        const nextOperand = operand[i + 1];

        switch (op) {
            case '+':
                result += nextOperand;
                break;
            case '-':
                result -= nextOperand;
                break;
            case '*':
                result *= nextOperand;
                break;
            case '//':
                result = Math.floor(result / nextOperand);
                break;
            case '**':
                result **= nextOperand;
                break;
        }
    }

    return result;
}
